//帮别人调
#include<bits/stdc++.h>
using namespace std;
const int N=1e5+1;
#define int long long 
int a[N];
int f[N][2];//f[i][1|0] 表示第i个数选或不选的最大值 
bool cmp(int x,int y){
	return x>y;
}
signed main(){
	ios::sync_with_stdio(false);
	cin.tie(0);
	cout.tie(0);
	int n,k;
	set<__int128> st;
	cin>>n>>k;
	for(int i=1;i<=n;i++){
		cin>>a[i];
	}
	sort(a+1,a+n+1,cmp);
	for(int i=1;i<=n;i++){
		if(st.count((__int128)a[i]*k)){
			f[i][1]=f[i-1][1];
		}else{
			st.insert((__int128)a[i]);
			f[i][1]=f[i-1][1]+1;
		}
		f[i][0]=f[i-1][0];
	}
	cout<<max(f[n][0],f[n][1]);
	return 0;
}
